const RANGE25 = Array.from({ length: 25 }, (_, i) => i + 1);
const API_HEADERS = {
  'content-type': 'application/json; charset=utf-8',
  'cache-control': 'no-store',
  'access-control-allow-origin': '*',
  'access-control-allow-methods': 'GET, POST, OPTIONS',
  'access-control-allow-headers': 'content-type'
};

function json(data, status = 200) {
  return new Response(JSON.stringify(data, null, 2), { status, headers: API_HEADERS });
}

function parseNumbers(value) {
  if (Array.isArray(value)) return value.map(Number).filter(Number.isFinite);
  return String(value || '')
    .split(/[^0-9]+/)
    .filter(Boolean)
    .map(Number)
    .filter(Number.isFinite);
}

function normalizeDraw(numbers, label = 'entrada') {
  const unique = [...new Set(numbers.map(Number))].sort((a, b) => a - b);
  if (unique.length !== 15) throw new Error(`${label}: informe exatamente 15 dezenas diferentes.`);
  if (unique.some(n => !Number.isInteger(n) || n < 1 || n > 25)) throw new Error(`${label}: todas as dezenas devem estar entre 1 e 25.`);
  return unique;
}

function normalizeRow(row, i) {
  if (Array.isArray(row)) return { contest: i + 1, date: '', numbers: normalizeDraw(row.slice(-15), `linha ${i + 1}`) };
  const contest = Number(row.contest || row.Concurso || row.CONCURSO || row.id || row.ID || i + 1);
  const date = String(row.date || row.Data || row.DATA || row.data || '');
  let nums = row.numbers || row.dezenas || row.Dezenas || row.DEZENAS;
  if (!nums) {
    nums = Object.keys(row)
      .filter(k => /bola|dezena|d\d+|^n\d+|^num/i.test(k))
      .sort((a, b) => String(a).localeCompare(String(b), 'pt-BR', { numeric: true }))
      .map(k => row[k]);
  }
  return { contest, date, numbers: normalizeDraw(nums, `linha ${i + 1}`) };
}

function parseDatasetText(text) {
  const raw = String(text || '').trim();
  if (!raw) return [];
  if (raw.startsWith('[') || raw.startsWith('{')) {
    const parsed = JSON.parse(raw);
    const rows = Array.isArray(parsed) ? parsed : (parsed.draws || parsed.results || parsed.data || []);
    return rows.map((row, i) => normalizeRow(row, i));
  }
  const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
  const output = [];
  for (let i = 0; i < lines.length; i++) {
    const nums = parseNumbers(lines[i]);
    if (nums.length >= 15) {
      const contest = nums.length >= 16 ? nums[0] : i + 1;
      output.push({ contest, date: '', numbers: normalizeDraw(nums.slice(-15), `linha ${i + 1}`) });
    }
  }
  return output;
}

function datasetSummary(draws, source = 'internal') {
  if (!draws.length) throw new Error('Dataset vazio ou inválido.');
  return {
    source,
    draws: draws.length,
    firstContest: draws[0]?.contest ?? 1,
    lastContest: draws[draws.length - 1]?.contest ?? draws.length,
    firstDate: draws[0]?.date || '',
    lastDate: draws[draws.length - 1]?.date || '',
    universe: '1-25',
    numbersPerDraw: 15
  };
}

async function readBody(request) {
  try { return await request.json(); }
  catch { return {}; }
}

function sum(arr) { return arr.reduce((a, b) => a + b, 0); }
function avg(arr) { return arr.length ? Number((sum(arr) / arr.length).toFixed(3)) : 0; }
function intersection(a, b) { const s = new Set(b); return a.filter(x => s.has(x)); }
function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }
function mulberry32(a) {
  return function () {
    a |= 0; a = a + 0x6D2B79F5 | 0;
    let t = Math.imul(a ^ a >>> 15, 1 | a);
    t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}
function hashSeed(s) {
  let h = 2166136261;
  for (const ch of String(s)) { h ^= ch.charCodeAt(0); h = Math.imul(h, 16777619); }
  return h >>> 0;
}
function sampleWeighted(items, weights, k, rng) {
  const pool = items.map((item, i) => ({ item, weight: Math.max(0.0001, weights[i] || 0.0001) }));
  const out = [];
  while (out.length < k && pool.length) {
    const total = pool.reduce((a, x) => a + x.weight, 0);
    let r = rng() * total;
    let idx = 0;
    for (; idx < pool.length; idx++) { r -= pool[idx].weight; if (r <= 0) break; }
    out.push(pool.splice(Math.min(idx, pool.length - 1), 1)[0].item);
  }
  return out.sort((a, b) => a - b);
}

function frequency(draws, windowSize = draws.length) {
  const slice = draws.slice(Math.max(0, draws.length - windowSize));
  const freq = Object.fromEntries(RANGE25.map(n => [n, 0]));
  for (const draw of slice) for (const n of draw.numbers) freq[n]++;
  return freq;
}
function delay(draws) {
  const out = Object.fromEntries(RANGE25.map(n => [n, draws.length]));
  for (let i = draws.length - 1; i >= 0; i--) {
    for (const n of draws[i].numbers) if (out[n] === draws.length) out[n] = draws.length - 1 - i;
  }
  return out;
}
function pairMatrix(draws, windowSize = 600) {
  const slice = draws.slice(Math.max(0, draws.length - windowSize));
  const matrix = Array.from({ length: 26 }, () => Array(26).fill(0));
  for (const draw of slice) {
    const nums = draw.numbers;
    for (let i = 0; i < nums.length; i++) for (let j = i + 1; j < nums.length; j++) {
      matrix[nums[i]][nums[j]]++; matrix[nums[j]][nums[i]]++;
    }
  }
  return matrix;
}
function transitionProfile(draws, windowSize = 500) {
  const start = Math.max(0, draws.length - windowSize - 1);
  const counts = {};
  for (let i = start; i < draws.length - 1; i++) {
    const hits = intersection(draws[i].numbers, draws[i + 1].numbers).length;
    counts[hits] = (counts[hits] || 0) + 1;
  }
  const entries = Object.entries(counts).map(([k, v]) => [Number(k), v]).sort((a, b) => b[1] - a[1]);
  return { distribution: counts, targetRepeat: entries[0]?.[0] || 9 };
}
function profile(numbers, lastDraw = []) {
  const even = numbers.filter(n => n % 2 === 0).length;
  const low = numbers.filter(n => n <= 13).length;
  return {
    even,
    odd: 15 - even,
    low,
    high: 15 - low,
    sum: sum(numbers),
    range: Math.max(...numbers) - Math.min(...numbers),
    repeatFromLast: lastDraw.length ? intersection(numbers, lastDraw).length : null
  };
}
function walletMetrics(wallet, lastDraw = []) {
  const profiles = wallet.map(g => profile(g.numbers, lastDraw));
  const used = new Set(wallet.flatMap(g => g.numbers));
  let overlapSum = 0, pairs = 0;
  for (let i = 0; i < wallet.length; i++) for (let j = i + 1; j < wallet.length; j++) {
    overlapSum += intersection(wallet[i].numbers, wallet[j].numbers).length; pairs++;
  }
  const byProfile = {};
  for (const g of wallet) byProfile[g.method] = (byProfile[g.method] || 0) + 1;
  return {
    count: wallet.length,
    avgSum: avg(profiles.map(p => p.sum)),
    avgEven: avg(profiles.map(p => p.even)),
    avgLow: avg(profiles.map(p => p.low)),
    avgRepeatFromLast: lastDraw.length ? avg(profiles.map(p => p.repeatFromLast)) : null,
    avgOverlap: pairs ? Number((overlapSum / pairs).toFixed(3)) : 0,
    coverage: used.size,
    missing: RANGE25.filter(n => !used.has(n)),
    byProfile
  };
}
function normalizeMap(map) {
  const vals = RANGE25.map(n => map[n] || 0);
  const min = Math.min(...vals), max = Math.max(...vals);
  return Object.fromEntries(RANGE25.map(n => [n, max === min ? 0.5 : ((map[n] || 0) - min) / (max - min)]));
}
function buildScores(draws, lastDraw) {
  const fAll = normalizeMap(frequency(draws));
  const fRecent = normalizeMap(frequency(draws, Math.min(200, draws.length)));
  const d = normalizeMap(delay(draws));
  const pairs = pairMatrix(draws, Math.min(600, draws.length));
  const pairRaw = Object.fromEntries(RANGE25.map(n => [n, lastDraw.length ? lastDraw.reduce((a, x) => a + pairs[n][x], 0) / lastDraw.length : 0]));
  const p = normalizeMap(pairRaw);
  const scores = {};
  for (const n of RANGE25) scores[n] = 0.28 * fRecent[n] + 0.18 * fAll[n] + 0.22 * d[n] + 0.20 * p[n] + 0.12;
  return { scores, delayNorm: d, transition: transitionProfile(draws) };
}
function scoreCandidate(nums, ctx, method, wallet) {
  const p = profile(nums, ctx.lastDraw);
  let score = nums.reduce((a, n) => a + ctx.scores[n], 0) / 15;
  score -= Math.abs(p.even - 7.2) * 0.025;
  score -= Math.abs(p.low - 8.0) * 0.022;
  score -= Math.abs(p.sum - 195) * 0.0025;
  if (p.repeatFromLast !== null) score -= Math.abs(p.repeatFromLast - ctx.transition.targetRepeat) * 0.030;
  if (method === 'DIVERSITY-SHIELD' && wallet.length) {
    const maxOverlap = Math.max(...wallet.map(g => intersection(nums, g.numbers).length));
    score -= Math.max(0, maxOverlap - 10) * 0.06;
  }
  if (method === 'TAIL-SPARK') score += nums.reduce((a, n) => a + ctx.delayNorm[n], 0) / 15 * 0.14;
  return score;
}
function makeCandidate(ctx, method, rng) {
  const weights = RANGE25.map(n => {
    let w = ctx.scores[n];
    if (method === 'CORE-TRANSITION' && ctx.lastDraw.includes(n)) w *= 1.28;
    if (method === 'DIVERSITY-SHIELD') w = 0.55 * w + 0.45;
    if (method === 'TAIL-SPARK') w = 0.45 * w + 0.55 * ctx.delayNorm[n] + 0.15;
    return Math.max(0.01, w);
  });
  if (ctx.lastDraw.length) {
    const target = clamp(ctx.transition.targetRepeat + Math.round((rng() - 0.5) * 2), 7, 11);
    const inLast = [...ctx.lastDraw];
    const outLast = RANGE25.filter(n => !ctx.lastDraw.includes(n));
    const a = sampleWeighted(inLast, inLast.map(n => weights[n - 1]), Math.min(target, 15), rng);
    const b = sampleWeighted(outLast, outLast.map(n => weights[n - 1]), 15 - a.length, rng);
    return [...a, ...b].sort((x, y) => x - y);
  }
  return sampleWeighted(RANGE25, weights, 15, rng);
}
function generateNexusWallet(draws, lastDraw, options = {}) {
  const seed = hashSeed(`${options.seed || ''}|${draws.length}|${lastDraw.join('-')}|${options.contest || ''}`);
  const rng = mulberry32(seed);
  const ctx = { ...buildScores(draws, lastDraw), lastDraw };
  const methods = [
    ...Array(6).fill('CORE-TRANSITION'),
    ...Array(6).fill('NEXUS-HYBRID'),
    ...Array(5).fill('DIVERSITY-SHIELD'),
    ...Array(3).fill('TAIL-SPARK')
  ];
  const wallet = [];
  for (let i = 0; i < 20; i++) {
    const method = methods[i];
    let best = null, bestScore = -Infinity;
    for (let t = 0; t < 120; t++) {
      const cand = makeCandidate(ctx, method, rng);
      const key = cand.join(',');
      if (wallet.some(g => g.key === key)) continue;
      const s = scoreCandidate(cand, ctx, method, wallet);
      if (s > bestScore) { best = cand; bestScore = s; }
    }
    const numbers = best || makeCandidate(ctx, method, rng);
    wallet.push({
      id: i + 1,
      method,
      numbers,
      key: numbers.join(','),
      profile: profile(numbers, lastDraw),
      score: Number(scoreCandidate(numbers, ctx, method, wallet).toFixed(5))
    });
  }
  for (const g of wallet) delete g.key;
  return {
    wallet,
    meta: { seed, methods: [...new Set(methods)], targetRepeat: ctx.transition.targetRepeat, datasetSize: draws.length, mode: 'research-experimental' },
    metrics: walletMetrics(wallet, lastDraw)
  };
}
function checkWallet(wallet, result) {
  const games = wallet.map((g, idx) => {
    const numbers = g.numbers || g;
    const hits = intersection(numbers, result);
    return {
      id: g.id || idx + 1,
      method: g.method || '',
      numbers,
      hits: hits.length,
      hitNumbers: hits,
      band: hits.length >= 15 ? '15' : hits.length >= 14 ? '14' : hits.length >= 13 ? '13' : hits.length >= 12 ? '12' : hits.length >= 11 ? '11' : '<11'
    };
  });
  const summary = {
    bestHit: Math.max(...games.map(g => g.hits)),
    hits11: games.filter(g => g.hits === 11).length,
    hits12: games.filter(g => g.hits === 12).length,
    hits13: games.filter(g => g.hits === 13).length,
    hits14: games.filter(g => g.hits === 14).length,
    hits15: games.filter(g => g.hits === 15).length,
    ge11: games.filter(g => g.hits >= 11).length,
    ge12: games.filter(g => g.hits >= 12).length,
    ge13: games.filter(g => g.hits >= 13).length,
    ge14: games.filter(g => g.hits >= 14).length
  };
  return { summary, games };
}
function getDrawsFromBody(body) {
  if (body.datasetText && String(body.datasetText).trim()) return { draws: parseDatasetText(body.datasetText), source: 'uploaded' };
  return { draws: DEFAULT_DRAWS, source: 'internal' };
}

async function handleApi(request, pathname) {
  if (request.method === 'OPTIONS') return new Response(null, { status: 204, headers: API_HEADERS });
  if (pathname === '/api/ping') return json({ ok: true, service: 'SIGMA NEXUS CORE API', mode: 'direct-upload-worker-v2.3', time: new Date().toISOString() });
  if (request.method !== 'POST') return json({ ok: false, error: 'Use POST para este endpoint.' }, 405);
  const body = await readBody(request);
  if (pathname === '/api/dataset/validate') {
    const hasUpload = body.datasetText && String(body.datasetText).trim();
    const draws = hasUpload ? parseDatasetText(body.datasetText) : DEFAULT_DRAWS;
    return json({ ok: true, summary: datasetSummary(draws, hasUpload ? 'uploaded' : 'internal'), errors: [] });
  }
  if (pathname === '/api/analyze') {
    const numbers = normalizeDraw(parseNumbers(body.numbers), 'evento');
    return json({ ok: true, numbers, profile: profile(numbers), message: 'Análise estrutural concluída.' });
  }
  if (pathname === '/api/generate') {
    const lastDraw = normalizeDraw(parseNumbers(body.numbers || body.lastDraw), 'último sorteio');
    const { draws, source } = getDrawsFromBody(body);
    if (draws.length < 50) throw new Error('Dataset insuficiente para o motor. Envie ao menos 50 concursos ou use a base interna.');
    const generated = generateNexusWallet(draws, lastDraw, { seed: body.seed, contest: body.contest });
    return json({
      ok: true,
      source: source === 'uploaded' ? 'dataset personalizado' : 'dataset interno 3719',
      dataset: datasetSummary(draws, source),
      contest: String(body.contest || '').trim() || 'não informado',
      lastDraw,
      ...generated,
      disclaimer: 'Saída experimental para auditoria estatística. Não há garantia de acerto, previsão ou recomendação financeira.'
    });
  }
  if (pathname === '/api/check') {
    const result = normalizeDraw(parseNumbers(body.result), 'resultado');
    const wallet = Array.isArray(body.wallet) ? body.wallet : [];
    if (!wallet.length) throw new Error('Carteira ausente. Gere os cenários antes da conferência.');
    return json({ ok: true, result, ...checkWallet(wallet, result) });
  }
  if (pathname === '/api/backtest') {
    const limit = clamp(Number(body.limit || 120), 20, 250);
    const minHistory = clamp(Number(body.minHistory || 200), 50, 1000);
    const draws = DEFAULT_DRAWS;
    const start = Math.max(minHistory, draws.length - limit - 1);
    const rows = [];
    for (let i = start; i < draws.length - 1; i++) {
      const history = draws.slice(0, i + 1);
      const last = draws[i].numbers;
      const target = draws[i + 1].numbers;
      const wallet = generateNexusWallet(history, last, { seed: `bt-${i}`, contest: draws[i].contest }).wallet;
      const chk = checkWallet(wallet, target);
      rows.push({ n: draws[i].contest, target: draws[i + 1].contest, bestHit: chk.summary.bestHit, ge13: chk.summary.ge13, ge14: chk.summary.ge14, hits15: chk.summary.hits15 });
    }
    const summary = {
      tests: rows.length,
      avgBestHit: avg(rows.map(r => r.bestHit)),
      walletsGe13: rows.filter(r => r.ge13 > 0).length,
      walletsGe14: rows.filter(r => r.ge14 > 0).length,
      wallets15: rows.filter(r => r.hits15 > 0).length,
      bestHitMax: Math.max(...rows.map(r => r.bestHit))
    };
    return json({ ok: true, summary, rows: rows.slice(-30), disclaimer: 'Backtest capado para execução serverless. Use auditoria local para bateria completa.' });
  }
  return json({ ok: false, error: 'Endpoint não encontrado.' }, 404);
}

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    try {
      if (url.pathname.startsWith('/api/')) return await handleApi(request, url.pathname);
      if (env && env.ASSETS && typeof env.ASSETS.fetch === 'function') return env.ASSETS.fetch(request);
      return new Response('SIGMA NEXUS CORE: assets binding ausente. Refaça o deploy em Cloudflare Pages.', { status: 500 });
    } catch (error) {
      return json({ ok: false, error: error?.message || 'Erro interno controlado no SIGMA Worker.' }, 400);
    }
  }
};
